import numpy as np
from sklearn.feature_extraction.text import CountVectorizer
from sklearn.linear_model import LogisticRegression
from sklearn.pipeline import make_pipeline
from flask import Flask, request, jsonify

app = Flask(__name__)
model = make_pipeline(CountVectorizer(), LogisticRegression())

@app.route('/predict_spam_probability', methods=['POST'])
def predict_spam_probability():
    data = request.get_json()
    email_text = data['email_text']
    spam_probability = model.predict_proba([email_text])[0][1]
    return jsonify({'spam_probability': spam_probability})

if __name__ == '__main__':
    X_train = ['example spam email', 'example non-spam email']
    y_train = [1, 0]  # 1 for spam, 0 for non-spam
    model.fit(X_train, y_train)
    app.run()